        Base() { print(); }   // bug: calls overridable method
        void print() { System.out.println("Base.print"); }
    }
    static class Derived extends Base {
        int value = 42;
        void print() { System.out.println("Derived.print: " + value); }
    }
    public static void main(String[] args) {
        new Derived();
    }
